import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"1.永恒猎手","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/射击类/荒野猎人/永恒猎手/1.永恒猎手.md","filePath":"4.资源分区/6.技艺及称号/射击类/荒野猎人/永恒猎手/1.永恒猎手.md"}'),o={name:"4.资源分区/6.技艺及称号/射击类/荒野猎人/永恒猎手/1.永恒猎手.md"};function d(_,a,l,i,b,c){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"_1-永恒猎手",tabindex:"-1"},[n("1.永恒猎手 "),e("a",{class:"header-anchor",href:"#_1-永恒猎手","aria-label":'Permalink to "1.永恒猎手"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002A")])])],-1),s('<h1 id="永恒猎手" tabindex="-1">永恒猎手 <a class="header-anchor" href="#永恒猎手" aria-label="Permalink to &quot;永恒猎手&quot;">​</a></h1><p>永恒猎手</p><p>他回来了…虽然他那冰冷的心脏已不会再跳动，他的肺部也不会再支撑呼吸，但他还是回来了，和他永世的伙伴一起，继续这场永无止境的追猎。</p><p>在你死亡并依照「朝生暮死」规则进行复活时，需额外再支付7500分，并在你复活后视为自动将血统位的原本血统按洗点规则退款并洗掉，永恒猎手将占据你的血统位。</p><p>永恒猎手将把你变成不死生物，这会令你无需再呼吸、进食、休息，且不会随着时间的自然流逝而死亡，同时，你也不再会拥有韧性槽，而是始终将你的完好转化为1.5倍结构值。</p><p>在获得永恒猎手后，你将可以制作「缝合怪」以作为猎兽，同时，若你本就拥有猎兽，则令其永久死亡并视为退款，也可以选择采集最多不超过其总价值7成的尸块材料用于制作缝合怪。</p><p>以下的每一项永恒猎手能力都必须在一次死亡并依照「朝生暮死」规则复活时额外支付等量分数才能获得，每次依照「朝生暮死」规则复活时只能选择一项能力购买，并遵循价格从低到高进行购买。</p><p>永恒追猎<br> 2600分<br> 现在，被你以弓箭射击所攻击的敌人还会额外被你标记，你将获得目标敌人的真实视野直至其离开你的敏感范围或你失明为止。<br> 此外，你在制造缝合怪检定时再额外获得等同于耐力附加*2的表现加值。<br> 此外，你可以在以弓箭射击时再额外选定一个在你射程范围内的目标，一并攻击之。</p><p>猎人印记<br> 5200分<br> 被你击伤的敌人将被你追猎到天涯海角，在你以弓箭射击对某目标造成伤害后，直至其完全治愈你对他造成的伤害和异常点前，你都可以得知他所在的具体位置，这是一个B级创伤来源的支配效果，表现为你借助他的感官得知他所在的位置。</p><p>穿心箭<br> 10400分<br> 一箭穿心，杀死你的敌人，就是这么简单。你获得一种新的基于弓箭射击的特殊部位攻击方式，即用弓箭射击对方心脏，这视为4点特殊部位减值的特殊部位。对方使用强韧豁免对抗你的伤害出目，并受到等同于二者差值的伤害，若其未对抗成功，则令其陷入力竭状态之中，这个效果持续存在，直至敌人恢复了所有你对其造成的伤害为止，这是一个B级创伤来源的效果。当你第二次对同一目标使用穿心箭时，若你造成的伤害超过对方的体积，则超过的部分每有1点就附带1点流血点数，使用标准豁免进行对抗。同时，你射出的穿心箭还将视为附带有【超级贯穿】和接触攻击，表现为锋利的箭头直接刺破护甲，直插心脏。</p><p>梦魇永存<br> 20800分<br> 你总是一次又一次的归来，一次又一次…现在，你在影片中的死亡将可以选择立即以「朝生暮死」规则复活，你在影片结束后若希望复活，则不再依照「朝生暮死」规则，而是立即复活不花费任何点数。在影片中的复活每花费一次点数，下一次价格便翻倍，影片结束清空倍数。<br> 每次你复活后，便将额外获得等同于决心附加成功*5点弓箭射击检定上的表现加值，同时提升等同于决心附加成功*2的结构值。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
